/**
 * Install Location API
 * 
 * Completes installation for selected location
 */

import { NextRequest, NextResponse } from 'next/server';
import { cookies } from 'next/headers';
import { InstallationService } from '@/lib/services/installation.service';
import { createAdminClient } from '@/lib/supabase/admin';

export async function POST(request: NextRequest) {
  try {
    const cookieStore = await cookies();
    const tempTokens = cookieStore.get('temp_tokens');

    if (!tempTokens) {
      return NextResponse.json(
        { error: 'No authentication data found' },
        { status: 401 }
      );
    }

    const tokens = JSON.parse(tempTokens.value);
    const { locationId } = await request.json();

    if (!locationId) {
      return NextResponse.json(
        { error: 'Location ID is required' },
        { status: 400 }
      );
    }

    // Create installation
    const installationService = new InstallationService();
    await installationService.createOrUpdateInstallation({
      locationId,
      companyId: tokens.user_info.companyId,
      userId: tokens.user_info.id,
      userEmail: tokens.user_info.email,
      userName: tokens.user_info.name,
      accessToken: tokens.access_token,
      refreshToken: tokens.refresh_token,
      expiresIn: tokens.expires_in,
    });

    // Log audit event
    const supabase = createAdminClient();
    await supabase.rpc('log_audit_event', {
      loc_id: locationId,
      evt_type: 'installation_completed',
      evt_data: {
        user_id: tokens.user_info.id,
        user_email: tokens.user_info.email,
      },
    });

    // Clear temp tokens
    const response = NextResponse.json({ success: true });
    response.cookies.delete('temp_tokens');
    
    // Set location context
    response.cookies.set('location_id', locationId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: 30 * 24 * 60 * 60, // 30 days
    });

    return response;
  } catch (error) {
    console.error('Installation error:', error);
    return NextResponse.json(
      { error: 'Installation failed' },
      { status: 500 }
    );
  }
}