/**
 * Installation Service
 * 
 * Manages app installations with idempotent operations
 */

import { createClient } from '@supabase/supabase-js';
import { TokenService } from './token.service';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;

export interface Installation {
  id: string;
  location_id: string;
  company_id: string;
  user_id: string;
  user_email: string;
  user_name: string;
  status: 'active' | 'inactive' | 'suspended';
  installed_at: string;
  uninstalled_at: string | null;
  subscription_status: 'trial' | 'active' | 'cancelled' | 'expired';
  feature_flags: Record<string, boolean>;
}

export class InstallationService {
  private supabase = createClient(supabaseUrl, supabaseServiceKey);
  private tokenService = new TokenService();
  
  /**
   * Create or update installation (idempotent)
   */
  async createOrUpdateInstallation(data: {
    locationId: string;
    companyId: string;
    userId: string;
    userEmail: string;
    userName: string;
    accessToken: string;
    refreshToken: string;
    expiresIn: number;
  }): Promise<Installation> {
    // Check if installation exists
    const { data: existing } = await this.supabase
      .from('installations')
      .select('*')
      .eq('location_id', data.locationId)
      .single();
    
    // Store tokens
    await this.tokenService.storeTokens(
      data.locationId,
      data.accessToken,
      data.refreshToken,
      data.expiresIn
    );
    
    if (existing) {
      // Update existing installation
      const { data: updated, error } = await this.supabase
        .from('installations')
        .update({
          user_id: data.userId,
          user_email: data.userEmail,
          user_name: data.userName,
          status: 'active',
          uninstalled_at: null,
          updated_at: new Date().toISOString(),
        })
        .eq('location_id', data.locationId)
        .select()
        .single();
      
      if (error) throw error;
      return updated;
    } else {
      // Create new installation
      const { data: created, error } = await this.supabase
        .from('installations')
        .insert({
          location_id: data.locationId,
          company_id: data.companyId,
          user_id: data.userId,
          user_email: data.userEmail,
          user_name: data.userName,
          status: 'active',
          subscription_status: 'trial',
          feature_flags: {
            webhooks_enabled: false,
            real_time_sync: false,
          },
        })
        .select()
        .single();
      
      if (error) throw error;
      return created;
    }
  }
  
  /**
   * Get installation by location ID
   */
  async getInstallation(locationId: string): Promise<Installation | null> {
    const { data, error } = await this.supabase
      .from('installations')
      .select('*')
      .eq('location_id', locationId)
      .single();
    
    if (error) {
      if (error.code === 'PGRST116') return null;
      throw error;
    }
    
    return data;
  }
  
  /**
   * Check if installation is active
   */
  async isInstallationActive(locationId: string): Promise<boolean> {
    const installation = await this.getInstallation(locationId);
    return installation?.status === 'active';
  }
  
  /**
   * Update feature flags
   */
  async updateFeatureFlags(
    locationId: string,
    flags: Record<string, boolean>
  ): Promise<void> {
    const { error } = await this.supabase
      .from('installations')
      .update({
        feature_flags: flags,
        updated_at: new Date().toISOString(),
      })
      .eq('location_id', locationId);
    
    if (error) throw error;
  }
  
  /**
   * Mark installation as inactive (soft delete)
   */
  async deactivateInstallation(locationId: string): Promise<void> {
    const { error } = await this.supabase
      .from('installations')
      .update({
        status: 'inactive',
        uninstalled_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      })
      .eq('location_id', locationId);
    
    if (error) throw error;
  }
}